'use strict';

const {
  MathFloor,
} = primordials;

const {
  validateNumber,
  validateObject,
} = require('internal/validators');

const kMicrosPerMilli = 1_000;
const kMaxSamplingIntervalUs = 0x7FFFFFFF;
const kMaxSamplingIntervalMs = kMaxSamplingIntervalUs / kMicrosPerMilli;
const kMaxSamplesUnlimited = 0xFFFF_FFFF;

function normalizeCpuProfileOptions(options = {}) {
  validateObject(options, 'options');

  // TODO(ishabi): add support for 'mode' and 'filterContext' options
  const {
    sampleInterval,
    maxBufferSize,
  } = options;

  let samplingIntervalMicros = 0;
  if (sampleInterval !== undefined) {
    validateNumber(sampleInterval,
                   'options.sampleInterval',
                   0,
                   kMaxSamplingIntervalMs);
    samplingIntervalMicros = MathFloor(sampleInterval * kMicrosPerMilli);
    if (sampleInterval > 0 && samplingIntervalMicros === 0) {
      samplingIntervalMicros = 1;
    }
  }

  const size = maxBufferSize;
  let normalizedMaxSamples = kMaxSamplesUnlimited;
  if (size !== undefined) {
    validateNumber(size,
                   'options.maxBufferSize',
                   1,
                   kMaxSamplesUnlimited);
    normalizedMaxSamples = MathFloor(size);
  }

  return {
    samplingIntervalMicros,
    maxSamples: normalizedMaxSamples,
  };
}

module.exports = {
  normalizeCpuProfileOptions,
};

'use strict';

const {
  validateBoolean,
  validateInteger,
  validateInt32,
  validateObject,
} = require('internal/validators');

const {
  kSamplingNoFlags,
  kSamplingForceGC,
  kSamplingIncludeObjectsCollectedByMajorGC,
  kSamplingIncludeObjectsCollectedByMinorGC,
} = internalBinding('v8');

function normalizeHeapProfileOptions(options = {}) {
  validateObject(options, 'options');
  const {
    sampleInterval = 512 * 1024,
    stackDepth = 16,
    forceGC = false,
    includeObjectsCollectedByMajorGC = false,
    includeObjectsCollectedByMinorGC = false,
  } = options;

  validateInteger(sampleInterval, 'options.sampleInterval', 1);
  validateInt32(stackDepth, 'options.stackDepth', 0);
  validateBoolean(forceGC, 'options.forceGC');
  validateBoolean(includeObjectsCollectedByMajorGC,
                  'options.includeObjectsCollectedByMajorGC');
  validateBoolean(includeObjectsCollectedByMinorGC,
                  'options.includeObjectsCollectedByMinorGC');

  let flags = kSamplingNoFlags;
  if (forceGC) flags |= kSamplingForceGC;
  if (includeObjectsCollectedByMajorGC) {
    flags |= kSamplingIncludeObjectsCollectedByMajorGC;
  }
  if (includeObjectsCollectedByMinorGC) {
    flags |= kSamplingIncludeObjectsCollectedByMinorGC;
  }

  return { sampleInterval, stackDepth, flags };
}

module.exports = {
  normalizeHeapProfileOptions,
};

'use strict';

const {
  ArrayPrototypeJoin,
  StringPrototypeSplit,
  StringPrototypeStartsWith,
} = primordials;

const { isAbsolute, relative, sep } = require('path');

// `path.sep` is required here because on Windows `path.resolve('/virtual')`
// produces 'C:\virtual' and all resolved paths use backslashes - a hardcoded
// '/' check would never match. The trailing-separator guard handles root
// mount points like 'C:\' so we don't end up with 'C:\\'.
function isUnderMountPoint(normalizedPath, mountPoint) {
  if (normalizedPath === mountPoint) {
    return true;
  }
  if (mountPoint === '/') {
    return StringPrototypeStartsWith(normalizedPath, '/');
  }
  const prefix = mountPoint[mountPoint.length - 1] === sep ?
    mountPoint : mountPoint + sep;
  return StringPrototypeStartsWith(normalizedPath, prefix);
}

// Returns a POSIX-style relative path the provider can consume. Uses
// `path.relative()` so Windows backslash paths are handled correctly, then
// re-joins with forward slashes for the provider's internal POSIX format.
function getRelativePath(normalizedPath, mountPoint) {
  if (normalizedPath === mountPoint) {
    return '/';
  }
  if (mountPoint === '/') {
    return normalizedPath;
  }
  const rel = relative(mountPoint, normalizedPath);
  const segments = StringPrototypeSplit(rel, sep);
  return '/' + ArrayPrototypeJoin(segments, '/');
}

module.exports = {
  isUnderMountPoint,
  getRelativePath,
  isAbsolutePath: isAbsolute,
};

'use strict';

const {
  TraceSigintWatchdog,
} = internalBinding('watchdog');

class SigintWatchdog extends TraceSigintWatchdog {
  _started = false;
  _effective = false;
  _onNewListener = (eve) => {
    if (eve === 'SIGINT' && this._effective) {
      super.stop();
      this._effective = false;
    }
  };
  _onRemoveListener = (eve) => {
    if (eve === 'SIGINT' && process.listenerCount('SIGINT') === 0 &&
        !this._effective) {
      super.start();
      this._effective = true;
    }
  };

  start() {
    if (this._started) {
      return;
    }
    this._started = true;
    // Prepend sigint newListener to remove stop watchdog before signal wrap
    // been activated. Also make sigint removeListener been ran after signal
    // wrap been stopped.
    process.prependListener('newListener', this._onNewListener);
    process.addListener('removeListener', this._onRemoveListener);

    if (process.listenerCount('SIGINT') === 0) {
      super.start();
      this._effective = true;
    }
  }

  stop() {
    if (!this._started) {
      return;
    }
    this._started = false;
    process.removeListener('newListener', this._onNewListener);
    process.removeListener('removeListener', this._onRemoveListener);

    if (this._effective) {
      super.stop();
      this._effective = false;
    }
  }
}


module.exports = {
  SigintWatchdog,
};

